declare module "*.css" {
  const css: Record<string, string>;
  export default css;
}

declare module "*.png" {
  const png: string;
  export default png;
}

declare module "*.svg" {
  const svg: string;
  export default svg;
}

declare module "*.jpg" {
  const jpg: string;
  export default jpg;
}

declare module "*.ico" {
  const ico: string;
  export default ico;
}
